sql:
SELECT metric_id, COUNT(*) AS total_non_faulty_rows
FROM non_faulty_rows
GROUP BY metric_id;

SELECT DISTINCT p.project_name
FROM projects p
JOIN faulty_rows fr ON p.project_id = fr.project_id;

external_knowledge:
- Each individual user refers to a unique `user_id`.;
- A running total signifies a cumulative count. This count includes the sum of all new projects analyzed by the user up to the current month.;
- Half-year refers to a 6-month period ending in the current month.;
- The projects are analyzed based on the `analysis_date` field in the `metric_analysis` table. The cumulative count resets for each `user_id`.;

sql:
SELECT COUNT(DISTINCT project_id) 
FROM software_metrics 
WHERE faulty_rows_with_data >= 50 AND rows_with_data > 1000;

SELECT name
FROM software_metrics
WHERE calibration_id = 1;

SELECT name, version 
FROM software_metrics 
WHERE percentage_faulty > (SELECT AVG(percentage_faulty) FROM software_metrics);

SELECT COUNT(faulty_rows_with_data) AS seeds_of_doubt
FROM software_metrics
WHERE project_id = 1 AND version = 'v1.0';

SELECT notification_id, message
FROM notifications
WHERE notification_type = 'metric update';

SELECT AVG(faulty_rows_with_data) AS average_faulty_rows
FROM software_metrics
WHERE project_id = 1;

SELECT tool_used
FROM metric_analysis
WHERE analysis_duration < 60;

SELECT COUNT(fault_id) AS total_faults
FROM faulty_rows
WHERE project_id = (SELECT project_id FROM projects ORDER BY start_date ASC LIMIT 1);

SELECT name, metric_value
FROM software_metrics
WHERE percentage_faulty < 50;

SELECT version, AVG(metric_value) AS average_metric_value
FROM software_metrics
GROUP BY version;

SELECT name, faulty_rows_with_data
FROM software_metrics
WHERE faulty_rows_with_data > (
    SELECT AVG(faulty_rows_with_data)
    FROM software_metrics
);

SELECT project_name, team_lead, start_date
FROM projects
WHERE project_id > 50;

SELECT DISTINCT p.*
FROM projects p
JOIN faulty_rows fr ON p.project_id = fr.project_id;

SELECT name, version
FROM software_metrics
ORDER BY collection_date DESC;
